content.css:
.table-container {
  width: 100%;
  height: 100%;
  overflow-x: auto;
  padding: 10px;
  box-sizing: border-box;
}
.pbi-table {
  border-collapse: collapse;
  table-layout: fixed;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 14px;
  background-color: #ffffff;
}
.table-header-row {
  background-color: #f0f0f0;
  border-bottom: 2px solid #d0d0d0;
}
.table-header-cell {
  padding: 0 12px;
  text-align: left;
  font-weight: bold;
  color: #333;
  border-right: 1px solid #d0d0d0;
  display: table-cell;
  vertical-align: middle;
}
.table-header-cell:last-child {
  border-right: none;
}
.table-data-row {
  border-bottom: 1px solid #e0e0e0;
}
.table-data-row:hover {
  background-color: #f9f9f9;
}
.table-category-cell {
  padding: 0 12px;
  font-weight: 500;
  color: #333;
  border-right: 1px solid #e0e0e0;
  background-color: #f5f5f5;
  display: table-cell;
  vertical-align: middle;
}
.table-data-cell {
  padding: 0 12px;
  text-align: right;
  color: #333;
  border-right: 1px solid #e0e0e0;
  display: table-cell;
  vertical-align: middle;
}
.table-data-cell:last-child {
  border-right: none;
}
.table-total-row {
  background-color: #e8e8e8;
  border-top: 2px solid #999;
  border-bottom: 2px solid #999;
}
.table-total-label-cell {
  padding: 0 12px;
  color: #333;
  border-right: 1px solid #999;
  display: table-cell;
  vertical-align: middle;
  text-underline-offset: 4px;
  text-decoration-thickness: 1px;
}
.table-total-cell {
  padding: 0 12px;
  text-align: right;
  color: #333;
  border-right: 1px solid #999;
  display: table-cell;
  vertical-align: middle;
  text-underline-offset: 4px;
  text-decoration-thickness: 1px;
}
.table-total-cell:last-child {
  border-right: none;
}
